import { HttpClient, HttpParams } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable, map } from 'rxjs';
import { environment } from '../../../environments/environment';

type QueryValue = string | number | boolean | null | undefined;
type QueryParams = Record<string, QueryValue>;

interface ApiEnvelope<T> {
  data: T;
}

@Injectable({ providedIn: 'root' })
export class ApiClientService {
  private http = inject(HttpClient);

  get<T>(path: string, params?: QueryParams): Observable<T> {
    return this.http
      .get<T | ApiEnvelope<T>>(this.buildUrl(path), {
        params: this.toHttpParams(params),
      })
      .pipe(map((response) => this.unwrap(response)));
  }

  post<TResponse, TBody>(path: string, body: TBody): Observable<TResponse> {
    return this.http
      .post<TResponse | ApiEnvelope<TResponse>>(this.buildUrl(path), body)
      .pipe(map((response) => this.unwrap(response)));
  }

  private unwrap<T>(response: T | ApiEnvelope<T>): T {
    if (response && typeof response === 'object' && 'data' in (response as ApiEnvelope<T>)) {
      return (response as ApiEnvelope<T>).data;
    }

    return response as T;
  }

  private buildUrl(path: string): string {
    const base = environment.api.baseUrl.replace(/\/+$/, '');
    const normalizedPath = path.startsWith('/') ? path : `/${path}`;
    return `${base}${normalizedPath}`;
  }

  private toHttpParams(params?: QueryParams): HttpParams | undefined {
    if (!params) return undefined;

    let httpParams = new HttpParams();
    Object.entries(params).forEach(([key, value]) => {
      if (value !== undefined && value !== null) {
        httpParams = httpParams.set(key, String(value));
      }
    });

    return httpParams;
  }
}
